export enum UserRole {
  ADMIN = 'ADMIN',
  DOCTOR = 'DOCTOR',
  PATIENT = 'PATIENT',
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  organization: string; // MSP (Membership Service Provider) ID
  publicKey: string;
}

export interface HealthRecord {
  id: string;
  patientId: string;
  doctorId: string;
  timestamp: number;
  type: 'DIAGNOSIS' | 'PRESCRIPTION' | 'LAB_RESULT' | 'VITAL_SIGNS';
  data: string;
  attachmentUrl?: string;
  hash: string;
}

export interface Transaction {
  txId: string;
  creator: string;
  timestamp: number;
  payload: HealthRecord;
  signature: string;
}

export interface Block {
  blockNumber: number;
  previousHash: string;
  currentHash: string;
  transactions: Transaction[];
  timestamp: number;
}

export interface BlockchainState {
  chain: Block[];
  pendingTransactions: Transaction[];
  worldState: Record<string, HealthRecord[]>; // patientId -> records
}

export type ViewType = 'DASHBOARD' | 'RECORDS' | 'EXPLORER' | 'IDENTITY' | 'ANALYTICS';

import { Block, Transaction, HealthRecord, BlockchainState, User } from '../types';

class BlockchainService {
  private state: BlockchainState;

  constructor() {
    this.state = this.initializeGenesis();
  }

  private initializeGenesis(): BlockchainState {
    const genesisRecord: HealthRecord = {
      id: '0',
      patientId: 'SYSTEM',
      doctorId: 'SYSTEM',
      timestamp: Date.now(),
      type: 'DIAGNOSIS',
      data: 'Genesis Block - Network Initialization',
      hash: '0'
    };

    const genesisTx: Transaction = {
      txId: 'tx_0',
      creator: 'NetworkAdmin',
      timestamp: Date.now(),
      payload: genesisRecord,
      signature: 'SIG_GENESIS'
    };

    const genesisBlock: Block = {
      blockNumber: 0,
      previousHash: '0',
      currentHash: this.calculateHash('0' + JSON.stringify(genesisTx)),
      transactions: [genesisTx],
      timestamp: Date.now()
    };

    return {
      chain: [genesisBlock],
      pendingTransactions: [],
      worldState: {}
    };
  }

  private calculateHash(data: string): string {
    // Simple mock hash for demonstration
    let hash = 0;
    for (let i = 0; i < data.length; i++) {
      const char = data.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash |= 0;
    }
    return Math.abs(hash).toString(16);
  }

  public async submitTransaction(record: HealthRecord, user: User): Promise<Transaction> {
    const txId = `tx_${Math.random().toString(36).substr(2, 9)}`;
    const tx: Transaction = {
      txId,
      creator: `${user.organization}:${user.name}`,
      timestamp: Date.now(),
      payload: record,
      signature: `SIG_${txId}`
    };

    this.state.pendingTransactions.push(tx);

    // In Fabric, endorsement/committing happens. We simulate a block every 1 transaction for immediate feedback.
    this.commitBlock();

    return tx;
  }

  private commitBlock() {
    if (this.state.pendingTransactions.length === 0) return;

    const lastBlock = this.state.chain[this.state.chain.length - 1];
    const newBlock: Block = {
      blockNumber: lastBlock.blockNumber + 1,
      previousHash: lastBlock.currentHash,
      transactions: [...this.state.pendingTransactions],
      timestamp: Date.now(),
      currentHash: ''
    };

    newBlock.currentHash = this.calculateHash(newBlock.previousHash + JSON.stringify(newBlock.transactions));

    // Update World State
    newBlock.transactions.forEach(tx => {
      const pId = tx.payload.patientId;
      if (!this.state.worldState[pId]) {
        this.state.worldState[pId] = [];
      }
      this.state.worldState[pId].push(tx.payload);
    });

    this.state.chain.push(newBlock);
    this.state.pendingTransactions = [];
  }

  public getState(): BlockchainState {
    return { ...this.state };
  }

  public getPatientRecords(patientId: string): HealthRecord[] {
    return this.state.worldState[patientId] || [];
  }
}

export const blockchainService = new BlockchainService();

import { GoogleGenAI } from "@google/genai";
import { HealthRecord } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeHealthRecords = async (records: HealthRecord[], patientName: string) => {
  const recordsSummary = records.map(r => 
    `Date: ${new Date(r.timestamp).toLocaleDateString()}, Type: ${r.type}, Data: ${r.data}`
  ).join('\n');

  const prompt = `
    As an AI Clinical Assistant, analyze the following medical records for patient "${patientName}".
    The records are retrieved from an immutable blockchain ledger.

    Records:
    ${recordsSummary}

    Please provide:
    1. A concise summary of the medical history.
    2. Identification of any worrying trends or patterns.
    3. Suggested follow-up questions for the next consultation.

    Format the output using clear Markdown headings and bullet points.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Failed to analyze records. Please try again later.";
  }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole, ViewType, BlockchainState } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import PatientRecords from './components/PatientRecords';
import BlockchainVisualizer from './components/BlockchainVisualizer';
import IdentityManagement from './components/IdentityManagement';
import { blockchainService } from './services/blockchainService';

const DEFAULT_USER: User = {
  id: 'doc_1',
  name: 'Dr. Sarah Mitchell',
  role: UserRole.DOCTOR,
  organization: 'Org1MSP (St. Mary Hospital)',
  publicKey: '0x71C765...d897'
};

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<User>(DEFAULT_USER);
  const [chainState, setChainState] = useState<BlockchainState>(blockchainService.getState());

  const refreshState = () => {
    setChainState(blockchainService.getState());
  };

  useEffect(() => {
    // Initial data refresh
    refreshState();
  }, []);

  const renderView = () => {
    switch (activeView) {
      case 'DASHBOARD':
        return <Dashboard chainState={chainState} currentUser={currentUser} />;
      case 'RECORDS':
        return <PatientRecords refreshState={refreshState} currentUser={currentUser} />;
      case 'EXPLORER':
        return <BlockchainVisualizer chain={chainState.chain} />;
      case 'IDENTITY':
        return <IdentityManagement currentUser={currentUser} setCurrentUser={setCurrentUser} />;
      default:
        return <Dashboard chainState={chainState} currentUser={currentUser} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeView={activeView} setActiveView={setActiveView} role={currentUser.role} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header currentUser={currentUser} chainLength={chainState.chain.length} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

