import React, { useState } from 'react';
import { HealthRecord, User, UserRole } from '../types';
import { blockchainService } from '../services/blockchainService';
import { analyzeHealthRecords } from '../services/geminiService';

interface PatientRecordsProps {
  refreshState: () => void;
  currentUser: User;
}

const PatientRecords: React.FC<PatientRecordsProps> = ({ refreshState, currentUser }) => {
  const [selectedPatient, setSelectedPatient] = useState('PATIENT_001');
  const [isAdding, setIsAdding] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);

  const [newRecord, setNewRecord] = useState({
    type: 'DIAGNOSIS' as HealthRecord['type'],
    data: '',
  });

  const records = blockchainService.getPatientRecords(selectedPatient);

  const handleAddRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    const record: HealthRecord = {
      id: Math.random().toString(36).substr(2, 9),
      patientId: selectedPatient,
      doctorId: currentUser.id,
      timestamp: Date.now(),
      type: newRecord.type,
      data: newRecord.data,
      hash: '' // Simplified for demo
    };

    await blockchainService.submitTransaction(record, currentUser);
    setNewRecord({ type: 'DIAGNOSIS', data: '' });
    setIsAdding(false);
    refreshState();
  };

  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeHealthRecords(records, selectedPatient);
    setAnalysisResult(result || "No analysis available.");
    setIsAnalyzing(false);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Health Ledger Records</h1>
          <p className="text-slate-500">Immutable clinical history for patient ID: {selectedPatient}</p>
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={runAiAnalysis}
            disabled={isAnalyzing || records.length === 0}
            className="px-4 py-2 bg-indigo-500 hover:bg-indigo-600 disabled:bg-indigo-300 text-white rounded-xl flex items-center transition-all shadow-lg shadow-indigo-100"
          >
            {isAnalyzing ? (
              <i className="fas fa-circle-notch fa-spin mr-2"></i>
            ) : (
              <i className="fas fa-magic mr-2"></i>
            )}
            AI Analysis
          </button>
          <button 
            onClick={() => setIsAdding(true)}
            className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-xl flex items-center transition-all shadow-lg shadow-blue-100"
          >
            <i className="fas fa-plus mr-2"></i>
            New Record
          </button>
        </div>
      </div>

      {analysisResult && (
        <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-6 relative">
          <button onClick={() => setAnalysisResult(null)} className="absolute top-4 right-4 text-indigo-400 hover:text-indigo-600">
            <i className="fas fa-times"></i>
          </button>
          <div className="flex items-start space-x-4">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600">
              <i className="fas fa-robot text-lg"></i>
            </div>
            <div className="flex-1">
              <h3 className="font-bold text-indigo-900 mb-2">AI Clinical Insight</h3>
              <div className="prose prose-sm prose-indigo text-indigo-800 whitespace-pre-line">
                {analysisResult}
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Date</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Type</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Clinical Notes</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Doctor</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Verification</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {records.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  <i className="fas fa-inbox text-4xl mb-4 block"></i>
                  No records found in the ledger for this patient.
                </td>
              </tr>
            ) : (
              records.map((record) => (
                <tr key={record.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                    {new Date(record.timestamp).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${
                      record.type === 'DIAGNOSIS' ? 'bg-blue-100 text-blue-700' :
                      record.type === 'PRESCRIPTION' ? 'bg-purple-100 text-purple-700' :
                      'bg-emerald-100 text-emerald-700'
                    }`}>
                      {record.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-900">
                    {record.data}
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600">
                    {record.doctorId === currentUser.id ? 'You' : record.doctorId}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center text-xs text-green-600 font-medium">
                      <i className="fas fa-check-circle mr-1.5"></i>
                      Verified
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-slideUp">
            <div className="p-8">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-slate-900">Endorse New Record</h2>
                <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600">
                  <i className="fas fa-times"></i>
                </button>
              </div>

              <form onSubmit={handleAddRecord} className="space-y-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Record Type</label>
                  <select 
                    value={newRecord.type}
                    onChange={(e) => setNewRecord({...newRecord, type: e.target.value as HealthRecord['type']})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="DIAGNOSIS">Diagnosis</option>
                    <option value="PRESCRIPTION">Prescription</option>
                    <option value="LAB_RESULT">Lab Result</option>
                    <option value="VITAL_SIGNS">Vital Signs</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Clinical Details</label>
                  <textarea 
                    required
                    value={newRecord.data}
                    onChange={(e) => setNewRecord({...newRecord, data: e.target.value})}
                    placeholder="Enter observations, diagnosis, or prescription details..."
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 h-32 resize-none"
                  ></textarea>
                </div>
                <div className="bg-blue-50 p-4 rounded-xl flex items-start space-x-3">
                  <i className="fas fa-info-circle text-blue-500 mt-0.5"></i>
                  <p className="text-xs text-blue-700 leading-relaxed">
                    Once submitted, this record will be cryptographically signed with your private key and proposed as a block to the Hyperledger Fabric network for immutability.
                  </p>
                </div>
                <div className="flex space-x-3 pt-4">
                  <button type="button" onClick={() => setIsAdding(false)} className="flex-1 py-3 border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors">
                    Cancel
                  </button>
                  <button type="submit" className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all">
                    Sign & Commit
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PatientRecords;

import React from 'react';
import { User, UserRole } from '../types';

interface IdentityManagementProps {
  currentUser: User;
  setCurrentUser: (user: User) => void;
}

const IdentityManagement: React.FC<IdentityManagementProps> = ({ currentUser, setCurrentUser }) => {
