    { role: UserRole.DOCTOR, icon: 'fa-user-md', desc: 'Can endorse medical records and propose updates to the ledger.' },
    { role: UserRole.PATIENT, icon: 'fa-user', desc: 'Can view their own records and manage access control permissions.' },
    { role: UserRole.ADMIN, icon: 'fa-user-shield', desc: 'Can manage organization channel memberships and peer nodes.' },
  ];

  const switchRole = (role: UserRole) => {
    setCurrentUser({
      ...currentUser,
      role: role,
      id: role === UserRole.DOCTOR ? 'doc_1' : role === UserRole.PATIENT ? 'pat_001' : 'admin_01'
    });
