          <h3 className="text-lg font-bold text-slate-800 mb-6">Current X.509 Certificate</h3>
          <div className="flex items-center space-x-6 mb-8">
            <div className="w-20 h-20 rounded-2xl bg-slate-900 flex items-center justify-center text-white text-3xl">
              <i className="fas fa-id-badge"></i>
            </div>
            <div>
              <p className="text-xl font-bold text-slate-900">{currentUser.name}</p>
              <p className="text-slate-500 font-medium">{currentUser.organization}</p>
              <div className="flex items-center mt-2 text-xs font-bold text-blue-600 px-2 py-1 bg-blue-50 rounded-full w-fit">
                <i className="fas fa-certificate mr-1.5"></i>
