          </div>

          <div className="space-y-4">
            <div className="p-4 bg-slate-50 rounded-xl font-mono text-xs text-slate-500 break-all leading-relaxed">
              ---BEGIN CERTIFICATE---<br/>
              MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEA71C765d897...<br/>
              ...{currentUser.publicKey}...<br/>
              ---END CERTIFICATE---
            </div>
            <button className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-colors">
              Renew Enrollment Certificate
            </button>
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-8 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Simulate Role Switch</h3>
          <p className="text-sm text-slate-500 mb-8 leading-relaxed">
