import React, { useState, useEffect } from 'react';
import { HealthRecord, User, UserRole } from '../types';
import { blockchainService } from '../services/blockchainService';
import { analyzeHealthRecords } from '../services/geminiService';

interface PatientRecordsProps {
  refreshState: () => void;
  currentUser: User;
}

const PatientRecords: React.FC<PatientRecordsProps> = ({ refreshState, currentUser }) => {
  const isPatient = currentUser.role === UserRole.PATIENT;
  const [selectedPatientId, setSelectedPatientId] = useState(isPatient ? currentUser.id : 'PATIENT_001');
  const [searchQuery, setSearchQuery] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);

  const [newRecord, setNewRecord] = useState({
    patientId: '',
    type: 'DIAGNOSIS' as HealthRecord['type'],
    data: '',
  });

  // Always bind patient to their own record
  useEffect(() => {
    if (isPatient) {
      setSelectedPatientId(currentUser.id);
    }
  }, [currentUser.id, isPatient]);

  const records = blockchainService.getPatientRecords(selectedPatientId);

  const handleAddRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    const targetPatient = isPatient ? currentUser.id : (newRecord.patientId || selectedPatientId);

    const record: HealthRecord = {
      id: `REC_${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      patientId: targetPatient,
      doctorId: currentUser.id,
      timestamp: Date.now(),
      type: newRecord.type,
      data: newRecord.data,
      hash: 'H_' + Math.random().toString(16).substr(2, 8)
    };

    await blockchainService.submitTransaction(record, currentUser);
    setNewRecord({ patientId: '', type: 'DIAGNOSIS', data: '' });
    setIsAdding(false);
    refreshState();
  };

  const runAiAnalysis = async () => {
    setIsAnalyzing(true);
    const result = await analyzeHealthRecords(records, selectedPatientId);
    setAnalysisResult(result || "No analysis available.");
    setIsAnalyzing(false);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">
            {isPatient ? 'My Health Ledger' : 'Clinical Record Management'}
          </h1>
          <p className="text-slate-500">
            {isPatient ? 'Securely viewing your immutable health history' : 'Verify and manage patient clinical data'}
          </p>
        </div>

        <div className="flex items-center space-x-3">
          {!isPatient && (
            <div className="relative group">
              <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors"></i>
              <input 
                type="text"
                placeholder="Lookup Patient ID..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && setSelectedPatientId(searchQuery)}
                className="bg-white border border-slate-200 rounded-xl pl-10 pr-4 py-2.5 text-sm outline-none focus:ring-4 focus:ring-blue-100 w-56 transition-all"
              />
            </div>
          )}

          <button 
            onClick={runAiAnalysis}
            disabled={isAnalyzing || records.length === 0}
            className="px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-xl flex items-center transition-all shadow-lg shadow-indigo-100 font-bold"
          >
            {isAnalyzing ? <i className="fas fa-circle-notch fa-spin mr-2"></i> : <i className="fas fa-magic mr-2"></i>}
            Analyze History
          </button>

          <button 
            onClick={() => setIsAdding(true)}
            className="px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl flex items-center transition-all shadow-lg shadow-blue-100 font-bold"
          >
            <i className="fas fa-plus mr-2"></i> New Record
          </button>
        </div>
      </div>

      <div className="bg-white p-6 rounded-[2rem] border border-slate-200 flex items-center justify-between shadow-sm">
        <div className="flex items-center space-x-4">
          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-xl ${isPatient ? 'bg-emerald-600' : 'bg-blue-600'}`}>
            <i className={`fas ${isPatient ? 'fa-user' : 'fa-hospital-user'} text-2xl`}></i>
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Authenticated Ledger Access</p>
            <p className="text-xl font-bold text-slate-800">{selectedPatientId}</p>
          </div>
        </div>
        <div className="hidden sm:flex items-center space-x-6">
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Records Count</p>
            <p className="text-lg font-bold text-slate-800">{records.length}</p>
          </div>
          <div className="h-10 w-[1px] bg-slate-100"></div>
          <div className="px-4 py-1.5 bg-green-50 text-green-600 rounded-xl text-[10px] font-black border border-green-100 tracking-wider">
            <i className="fas fa-shield-alt mr-2"></i> LEDGER VERIFIED
          </div>
        </div>
      </div>

      {analysisResult && (
        <div className="bg-gradient-to-br from-indigo-50 to-white border border-indigo-100 rounded-[2.5rem] p-10 relative shadow-sm border-l-8 border-l-indigo-500">
          <button onClick={() => setAnalysisResult(null)} className="absolute top-6 right-6 text-indigo-200 hover:text-indigo-600 transition-colors">
            <i className="fas fa-times-circle text-2xl"></i>
          </button>
          <div className="flex items-start space-x-8">
            <div className="w-16 h-16 rounded-3xl bg-indigo-600 flex items-center justify-center text-white shadow-2xl shadow-indigo-200">
              <i className="fas fa-robot text-3xl"></i>
            </div>
            <div className="flex-1">
              <h3 className="text-2xl font-bold text-indigo-900 mb-6">AI Clinical Insights (Gemini Pro)</h3>
              <div className="prose prose-sm prose-indigo text-indigo-800/90 whitespace-pre-line leading-relaxed text-base">
                {analysisResult}
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Transaction Metadata</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Classification</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Clinical Findings</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Endorsed By</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Network Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {records.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-8 py-24 text-center text-slate-400">
                    <div className="mb-4 text-6xl opacity-10"><i className="fas fa-file-medical-alt"></i></div>
                    <p className="font-bold text-lg">No blockchain transactions found.</p>
                    <p className="text-sm">Submit a new entry to commit it to the immutable ledger.</p>
                  </td>
                </tr>
              ) : (
                records.slice().reverse().map((record) => (
                  <tr key={record.id} className="group hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-7">
                      <p className="text-sm font-black text-slate-900">{new Date(record.timestamp).toLocaleDateString()}</p>
                      <p className="text-[10px] font-mono text-slate-400 mt-1.5 bg-slate-50 px-2 py-0.5 rounded w-fit">{record.id}</p>
                    </td>
                    <td className="px-8 py-7">
                      <span className={`inline-flex items-center px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${
                        record.type === 'DIAGNOSIS' ? 'bg-blue-100 text-blue-700' :
                        record.type === 'PRESCRIPTION' ? 'bg-purple-100 text-purple-700' :
                        'bg-emerald-100 text-emerald-700'
                      }`}>
                        {record.type}
                      </span>
                    </td>
                    <td className="px-8 py-7">
                      <p className="text-sm text-slate-700 font-medium leading-relaxed max-w-md">{record.data}</p>
                    </td>
                    <td className="px-8 py-7">
                      <div className="flex items-center">
                        <div className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-500 mr-3 border border-slate-200">
                          {record.doctorId.substring(0, 2)}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-slate-800">{record.doctorId === currentUser.id ? 'CURRENT_SESSION' : record.doctorId}</p>
                          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Endorser Node</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-7">
                      <div className="flex items-center text-[10px] text-emerald-600 font-black bg-emerald-50 px-3 py-1.5 rounded-xl w-fit border border-emerald-100">
                        <i className="fas fa-link mr-2"></i>
                        COMMITTED
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-slate-950/70 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-2xl overflow-hidden animate-scaleIn">
            <div className="p-12">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h2 className="text-3xl font-bold text-slate-900 mb-2">Commit Record</h2>
                  <p className="text-slate-500">Sign and propose a new clinical transaction to the network.</p>
                </div>
                <button onClick={() => setIsAdding(false)} className="w-12 h-12 rounded-full hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>

              <form onSubmit={handleAddRecord} className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Target Patient Identity</label>
                    <input 
                      required
                      disabled={isPatient}
                      type="text"
                      value={isPatient ? currentUser.id : (newRecord.patientId || selectedPatientId)}
                      onChange={e => setNewRecord({...newRecord, patientId: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-[1.25rem] px-6 py-5 outline-none focus:ring-4 focus:ring-blue-100 transition-all font-bold disabled:bg-slate-100 disabled:text-slate-400"
                      placeholder="e.g. PATIENT_XYZ"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Record Classification</label>
                    <select 
                      value={newRecord.type}
                      onChange={(e) => setNewRecord({...newRecord, type: e.target.value as HealthRecord['type']})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-[1.25rem] px-6 py-5 outline-none appearance-none font-bold"
                    >
                      <option value="DIAGNOSIS">Clinical Diagnosis</option>
                      <option value="PRESCRIPTION">Prescription / Medication</option>
                      <option value="LAB_RESULT">Laboratory Findings</option>
                      <option value="VITAL_SIGNS">Vital Sign Records</option>
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Clinical Findings Payload</label>
                  <textarea 
                    required
                    value={newRecord.data}
                    onChange={(e) => setNewRecord({...newRecord, data: e.target.value})}
                    placeholder="Enter detailed clinical observations..."
                    className="w-full bg-slate-50 border border-slate-200 rounded-[1.25rem] px-6 py-5 outline-none focus:ring-4 focus:ring-blue-100 h-48 resize-none transition-all font-medium"
                  ></textarea>
                </div>

                <div className="bg-blue-600/5 p-6 rounded-[1.5rem] flex items-center space-x-6 border border-blue-600/10">
                  <div className="w-12 h-12 rounded-2xl bg-blue-600 text-white flex items-center justify-center shadow-lg">
                    <i className="fas fa-fingerprint text-xl"></i>
                  </div>
                  <div className="flex-1">
                    <p className="text-[10px] text-blue-600 font-black uppercase tracking-widest mb-1">Cryptographic Endorsement</p>
                    <p className="text-xs text-slate-600 leading-relaxed font-bold">
                      Signing with <span className="text-blue-700">{currentUser.publicKey.substring(0, 16)}...</span>
                      <br/>Authorized via <span className="text-blue-700">{currentUser.organization}</span>
                    </p>
                  </div>
                </div>

                <div className="pt-4">
                  <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-[1.5rem] font-black uppercase tracking-[0.2em] hover:bg-black shadow-2xl transition-all active:scale-[0.98]">
                    Sign & Commit Transaction
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

