  const menuItems = [
    { id: 'DASHBOARD', label: 'Network Health', icon: 'fa-chart-pie', roles: [UserRole.ADMIN, UserRole.DOCTOR, UserRole.PATIENT] },
    { 
      id: 'RECORDS', 
      label: role === UserRole.PATIENT ? 'My Records' : 'Clinical Manager', 
      icon: 'fa-file-medical', 
      roles: [UserRole.DOCTOR, UserRole.PATIENT] 
    },
    { id: 'EXPLORER', label: 'Ledger Explorer', icon: 'fa-cubes', roles: [UserRole.ADMIN, UserRole.DOCTOR] },
    { id: 'IDENTITY', label: 'Identity & CA', icon: 'fa-id-card', roles: [UserRole.ADMIN, UserRole.DOCTOR, UserRole.PATIENT] },
    { id: 'REPORT', label: 'Project Report', icon: 'fa-file-alt', roles: [UserRole.ADMIN, UserRole.DOCTOR] },
  ];

  const filteredItems = menuItems.filter(item => item.roles.includes(role));

  return (
    <aside className="w-64 bg-slate-950 text-white flex flex-col hidden md:flex shrink-0">
      <div className="p-8 flex items-center space-x-3">
        <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/20">
          <i className="fas fa-link text-lg"></i>
        </div>
        <div>
          <span className="text-xl font-black tracking-tighter">HEALTH<span className="text-blue-500">LEDGER</span></span>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-none">V2.0 PRO</p>
        </div>
      </div>

      <nav className="flex-1 px-4 py-8 space-y-2">
        {filteredItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveView(item.id as ViewType)}
            className={`w-full flex items-center space-x-3 px-4 py-3.5 rounded-xl transition-all duration-200 ${
              activeView === item.id 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' 
                : 'text-slate-500 hover:bg-slate-900 hover:text-white'
            }`}
          >
            <i className={`fas ${item.icon} w-5 text-sm ${activeView === item.id ? 'text-white' : 'text-slate-600'}`}></i>
            <span className="font-bold text-sm">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-6">
        <div className="bg-slate-900 rounded-2xl p-4 border border-slate-800">
          <div className="flex items-center space-x-2 text-[10px] text-green-400 font-black mb-3">
            <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></div>
            <span className="tracking-[0.2em] uppercase">Channel: main-ehr</span>
          </div>
          <p className="text-[10px] text-slate-500 font-medium mb-1">Active Peer:</p>
          <p className="text-xs font-mono text-slate-300 truncate">peer0.org1.hospital:7051</p>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { User, UserRole, ViewType, BlockchainState } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import PatientRecords from './components/PatientRecords';
import BlockchainVisualizer from './components/BlockchainVisualizer';
import IdentityManagement from './components/IdentityManagement';
import ProjectReport from './components/ProjectReport';
import { blockchainService } from './services/blockchainService';

const INITIAL_DOCTOR: User = {
  id: 'DOC_MITCHELL',
  name: 'Dr. Sarah Mitchell',
  role: UserRole.DOCTOR,
  organization: 'HospitalOrg1.MSP',
  publicKey: 'cert_771c765d897'
};

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('DASHBOARD');
  const [currentUser, setCurrentUser] = useState<User>(INITIAL_DOCTOR);
  const [chainState, setChainState] = useState<BlockchainState>(blockchainService.getState());

  const refreshState = () => {
    setChainState(blockchainService.getState());
  };

  useEffect(() => {
    refreshState();
  }, []);

  const renderView = () => {
    switch (activeView) {
      case 'DASHBOARD':
        return <Dashboard chainState={chainState} currentUser={currentUser} />;
      case 'RECORDS':
        return <PatientRecords refreshState={refreshState} currentUser={currentUser} />;
      case 'EXPLORER':
        return <BlockchainVisualizer chain={chainState.chain} />;
      case 'IDENTITY':
        return <IdentityManagement currentUser={currentUser} setCurrentUser={setCurrentUser} />;
      case 'REPORT':
        return <ProjectReport />;
      default:
        return <Dashboard chainState={chainState} currentUser={currentUser} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeView={activeView} setActiveView={setActiveView} role={currentUser.role} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header currentUser={currentUser} chainLength={chainState.chain.length} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-7xl mx-auto">
            {renderView()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

